export async function decide_boyfriend(
  ctx: TrainingContext,
  character: Character
): Promise<void> {
  await decide_boy_name, arg, 0(ctx, character);
}

export async function decide_sexfriend(
  ctx: TrainingContext,
  character: Character
): Promise<void> {
  await decide_boy_name, arg, 1(ctx, character);
}

